class Solution:
    def maxProfit(self, prices, fee):
        import functools
        n = len(prices)
        import sys
        sys.setrecursionlimit(100000)
        @functools.lru_cache(maxsize=None)
        def best(i, holding):
            if i == n:
                return 0
            skip = best(i + 1, holding)
            if holding:
                act = prices[i] - fee + best(i + 1, False)
            else:
                act = -prices[i] + best(i + 1, True)
            return max(skip, act)
        return best(0, False)

